class Solution:
    def maxPartitionsAfterOperations(self, s: str, k: int) -> int:
        # Базовый жадный подсчёт числа разбиений строки
        def count_partitions(t: str) -> int:
            parts = 0
            seen = set()
            for ch in t:
                if ch not in seen and len(seen) == k:
                    parts += 1
                    seen = {ch}
                else:
                    seen.add(ch)
            return parts + (1 if seen else 0)

        n = len(s)
        ans = count_partitions(s)  # вариант без изменений

        # Перебираем позицию и замену; O(26 * n^2), но корректно
        # Можно ускорить при необходимости, но сейчас приоритет — правильность.
        
        if k == 1:
            return len(s)
        
        for i in range(n):
            for c_ord in range(26):
                c = chr(97 + c_ord)
                if c == s[i]:
                    continue
                t = s[:i] + c + s[i + 1 :]
                ans = max(ans, count_partitions(t))

        return ans

if __name__ == "__main__":
    solution = Solution()
    s = ""
    print(solution.maxPartitionsAfterOperations(s, 1))